const syncedAt = new Date().toISOString();
const allCampaigns = [];
for (const item of $input.all()) {
  let campaigns = [];
  try {
    let raw = item.json.data;
    if (typeof raw === 'string') raw = JSON.parse(raw);
    if (raw && raw.data) { const d = raw.data; campaigns = Array.isArray(d) ? d : [d]; }
    else if (Array.isArray(raw)) campaigns = raw;
  } catch(e) { campaigns = []; }
  for (const c of campaigns) {
    if (!c || !c.id) continue;
    const attrs = c.attributes || {};
    const strategy = attrs.send_strategy || {};
    const staticOpts = strategy.options_static || {};
    allCampaigns.push({
      campaign_id: c.id,
      campaign_name: attrs.name || '',
      status: attrs.status || '',
      archived: attrs.archived || false,
      send_time: staticOpts.datetime || attrs.send_time || null,
      created_at: attrs.created_at || null,
      updated_at: attrs.updated_at || null,
      synced_at: syncedAt
    });
  }
}
if (allCampaigns.length === 0) return [{ json: { message: 'No campaigns', synced_at: syncedAt } }];
return allCampaigns.map(c => ({ json: c }));

const syncedAt = new Date().toISOString();
const today = new Date().toISOString().split('T')[0];
const allLists = [];
for (const item of $input.all()) {
  let lists = [];
  try {
    let raw = item.json.data;
    if (typeof raw === 'string') raw = JSON.parse(raw);
    if (raw && raw.data) { const d = raw.data; lists = Array.isArray(d) ? d : [d]; }
    else if (Array.isArray(raw)) lists = raw;
  } catch(e) { lists = []; }
  for (const l of lists) {
    if (!l || !l.id) continue;
    const attrs = l.attributes || {};
    allLists.push({
      date: today,
      list_id: l.id,
      list_name: attrs.name || '',
      created: attrs.created || null,
      updated: attrs.updated || null,
      synced_at: syncedAt
    });
  }
}
if (allLists.length === 0) return [{ json: { message: 'No lists', synced_at: syncedAt } }];
return allLists.map(l => ({ json: l }));

const allCampaigns = [];
for (const item of $input.all()) {
  let campaigns = [];
  try {
    let raw = item.json.data;
    if (typeof raw === 'string') raw = JSON.parse(raw);
    if (raw && raw.data) { const d = raw.data; campaigns = Array.isArray(d) ? d : [d]; }
    else if (Array.isArray(raw)) campaigns = raw;
  } catch(e) { campaigns = []; }
  for (const c of campaigns) {
    if (!c || !c.id) continue;
    const attrs = c.attributes || {};
    const strategy = attrs.send_strategy || {};
    const staticOpts = strategy.options_static || {};
    allCampaigns.push({ json: { campaign_id: c.id, campaign_name: attrs.name || '', send_time: staticOpts.datetime || null, status: attrs.status || '' } });
  }
}
return allCampaigns;

const syncedAt = new Date().toISOString();
const results = [];
for (const item of $input.all()) {
  let messages = [];
  try {
    let raw = item.json.data;
    if (typeof raw === 'string') raw = JSON.parse(raw);
    if (raw && raw.data) { const d = raw.data; messages = Array.isArray(d) ? d : [d]; }
    else if (Array.isArray(raw)) messages = raw;
  } catch(e) { messages = []; }
  for (const msg of messages) {
    if (!msg || !msg.id) continue;
    const attrs = msg.attributes || {};
    const content = attrs.content || {};
    const rels = msg.relationships || {};
    const campaignRel = rels.campaign || {};
    const campaignData = campaignRel.data || {};
    results.push({ json: { message_id: msg.id, campaign_id: campaignData.id || '', subject_line: content.subject || '', from_email: content.from_email || '', from_label: content.from_label || '', synced_at: syncedAt } });
  }
}
if (results.length === 0) return [{ json: { message: 'No messages', synced_at: syncedAt } }];
return results;

const raw = items[0].json;
let parsed = {};
if (typeof raw.data === 'string') {
  try { parsed = JSON.parse(raw.data); } catch(e) {}
} else {
  parsed = raw.data || raw;
}

let metrics = [];
if (Array.isArray(parsed.data)) metrics = parsed.data;
else if (Array.isArray(parsed)) metrics = parsed;

let metricId = null;
for (var i = 0; i < metrics.length; i++) {
  var name = (metrics[i].attributes && metrics[i].attributes.name) || '';
  if (name.toLowerCase().indexOf('placed order') !== -1) { metricId = metrics[i].id; break; }
}
if (!metricId && metrics.length > 0) metricId = metrics[0].id;
if (!metricId) return [{ json: { error: 'No metric found', count: metrics.length } }];
return [{ json: { conversion_metric_id: metricId, total_metrics: metrics.length } }];

const syncedAt = new Date().toISOString();
const today = new Date().toISOString().split('T')[0];
const results = [];

for (const item of $input.all()) {
  let raw = item.json;
  if (typeof raw.data === 'string') {
    try { raw = JSON.parse(raw.data); } catch(e) {}
  }

  let reportResults = [];
  if (raw.data && raw.data.attributes && raw.data.attributes.results) {
    reportResults = raw.data.attributes.results;
  } else if (raw.attributes && raw.attributes.results) {
    reportResults = raw.attributes.results;
  } else if (raw.results) {
    reportResults = raw.results;
  }

  for (var i = 0; i < reportResults.length; i++) {
    var r = reportResults[i];
    var stats = r.statistics || {};
    var groupings = r.groupings || {};

    results.push({ json: {
      date: today,
      campaign_id: groupings.campaign_id || '',
      campaign_name: '',
      send_date: null,
      sends: parseInt(stats.recipients || 0) || 0,
      deliveries: 0,
      opens: parseInt(stats.opens || 0) || 0,
      unique_opens: parseInt(stats.opens_unique || 0) || 0,
      open_rate: parseFloat(stats.open_rate || 0) || 0,
      clicks: parseInt(stats.clicks || 0) || 0,
      unique_clicks: parseInt(stats.clicks_unique || 0) || 0,
      click_rate: parseFloat(stats.click_rate || 0) || 0,
      unsubscribes: parseInt(stats.unsubscribes || 0) || 0,
      bounces: 0,
      revenue: parseFloat(stats.conversion_value || 0) || 0,
      conversions: parseInt(stats.conversions || 0) || 0,
      synced_at: syncedAt
    }});
  }
}

if (results.length === 0) return [{ json: { message: 'No metrics data', synced_at: syncedAt } }];
return results;

const metricId = items[0].json.conversion_metric_id;
if (!metricId) return [{ json: { error: 'No metric ID received', input: items[0].json } }];

return [{ json: {
  requestBody: {
    data: {
      type: "campaign-values-report",
      attributes: {
        timeframe: { key: "last_30_days" },
        conversion_metric_id: metricId,
        filter: "equals(send_channel,'email')",
        statistics: [
          "opens", "opens_unique", "open_rate",
          "clicks", "clicks_unique", "click_rate",
          "unsubscribes", "unsubscribe_rate",
          "recipients", "conversions",
          "conversion_rate", "conversion_value",
          "revenue_per_recipient"
        ]
      }
    }
  }
}}];
